AppNotes.Digital_Up_Converter.duc_test.m.source_code:
int main() {

    ofstream fp_result("out.dat", ofstream::out);
    fp_result.precision(25);
    fp_result.width(30);

    double tmp;

    const int nofset = 10;

    DATA_T din_i[nofset][L_INPUT];
    DATA_T din_q[nofset][L_INPUT];
    DATA_T dout[nofset][L_OUTPUT];
    DATA_T swout[nofset][L_OUTPUT];

    incr_t incr;
    // incr = 303.33333*pow(2,31-11);
    incr = 303.33333 * pow(2, -11);

    int jj = 0;
    float diff;
    int err_cnt = 0;

    for (int i = 0; i < nofset; i++) {
        for (int k = 0; k < L_INPUT; k++) {
            tmp = cos(2 * M_PI * (0.5 + (double)jj * 33) / (1024));
            din_i[i][k] = tmp;

#if 0
            tmp = 0.3*cos(2*M_PI*(0.5+(double)jj*10)/(1024));
            din_q[i][k] = tmp;
#endif
            tmp = sin(2 * M_PI * (0.5 + (double)jj * 33) / (1024));
            din_q[i][k] = tmp;

            jj++;
        }

        duc(din_i[i], din_q[i], dout[i], incr);
        duc_sw(din_i[i], din_q[i], swout[i], incr);

        // compare with expected
        for (int k = 0; k < L_OUTPUT; k++) {
            diff = dout[i][k] - swout[i][k];
            fp_result << dout[i][k] << ", " << swout[i][k] << endl;
            if (diff != 0)
                err_cnt++;
        }
    }

    if (diff == 0) {
        cout << "============== Test passed " << endl;
        return 0;
    } else {
        cout << "============== Test failed, error count =  " << err_cnt
             << endl;
        return 1;
    }
}

AppNotes.Digital_Up_Converter.fir.proces.source_code:
    void process(DATA_T din, DATA_T* dout0, DATA_T* dout1) {

#pragma HLS array_reshape variable = sr complete
#pragma HLS array_reshape variable = coeff complete dim = 0

        acc = 0;
    LOOP_MAC:
        for (int i = 0; i < l_NONZERO - 1; i++) {
            acc = MAC_preadd(sr[i], sr[l_TDL - 1 - i], coeff[i], acc);
        }

    LOOP_SR:
        for (int i = l_TDL - 1; i > 0; i--) {
            sr[i] = sr[i - 1];
        }

        sr[0] = din;

        *dout0 = acc;
        *dout1 = coeff[l_NONZERO - 1] * sr[l_NONZERO - 1];
    }

    void process_frame(DATA_T din[l_INPUT], DATA_T dout[2 * l_INPUT]) {

        DATA_T dout0, dout1;

    L_process_frame:
        for (int i = 0; i < l_INPUT; i++) {
#pragma HLS pipeline II = II_GOAL rewind
            process(din[i], &dout0, &dout1);
            dout[2 * i] = dout0;
            dout[2 * i + 1] = dout1;
        }
    }

AppNotes.Digital_Up_Converter.fir.init.source_code:
void init(const COEF_T cin[]) {

    bool scale = 1;
    COEF_T gain = scale ? 2 : 1;

    for (int i = 0; i < l_NONZERO - 1; i++) {
        coeff[i] = gain * cin[2 * i];
    }

    int i = l_NONZERO - 1;
    coeff[i] = gain * cin[2 * i - 1];
};

Array.array_partition_block_cyclic.matmu.source_code:
void matmul_partition(int* in1, int* in2, int* out_r, int dim, int rep_count) { // Matrix Dimension. Assuming Square Matrix
#pragma HLS INTERFACE m_axi port = in1 depth = 256
#pragma HLS INTERFACE m_axi port = in2 depth = 256
#pragma HLS INTERFACE m_axi port = out_r depth = 256

    int A[MAX_DIM * MAX_DIM];
    int B[MAX_DIM * MAX_DIM];
    int C[MAX_DIM * MAX_DIM];
// Cyclic Partition for A as matrix multiplication needs row-wise parallel
// access
#pragma HLS ARRAY_PARTITION variable = A dim = 1 cyclic factor = 16
// Block Partition for B as matrix multiplication needs column-wise parallel
// access
#pragma HLS ARRAY_PARTITION variable = B dim = 1 block factor = 16

// As A and B Matrix are partitioned with the factor of MAX_DIM, so to get
// parallel row/column access, input square matrix[dimXdim] should be written
// into local Array in MATRIX[MAX_DIM * MAX_DIM] format

// Burst read for matrix A
// Auto-pipeline is going to apply pipeline to these loops
readA:
    for (int itr = 0, i = 0, j = 0; itr < dim * dim; itr++, j++) {
#pragma HLS LOOP_TRIPCOUNT min = c_dim* c_dim max = c_dim * c_dim
        if (j == dim) {
            j = 0;
            i++;
        }
        A[i * MAX_DIM + j] = in1[itr];
    }

// Burst read for matrix B
readB:
    for (int itr = 0, i = 0, j = 0; itr < dim * dim; itr++, j++) {
#pragma HLS LOOP_TRIPCOUNT min = c_dim* c_dim max = c_dim * c_dim
        if (j == dim) {
            j = 0;
            i++;
        }
        B[i * MAX_DIM + j] = in2[itr];
    }

loop2:
    for (int x = 0; x < rep_count; x++) {
#pragma HLS LOOP_TRIPCOUNT min = 1 max = 1
    lreorder1:
        for (int i = 0; i < dim; i++) {
#pragma HLS LOOP_TRIPCOUNT min = c_dim max = c_dim
        // As A and B are partition correctly so loop pipelining is applied
        // at 2nd level loop and which will eventually unroll the lower loop
        lreorder2:
            for (int j = 0; j < dim; j++) {
#pragma HLS LOOP_TRIPCOUNT min = c_dim max = c_dim
                int result = 0;
            lreorder3:
                for (int k = 0; k < MAX_DIM; k++) {
                    //#pragma HLS LOOP_TRIPCOUNT min = c_dim max = c_dim
                    result += A[i * MAX_DIM + k] * B[k * MAX_DIM + j];
                }
                C[i * MAX_DIM + j] = result;
            }
        }
    }

// Burst write from output matrices to global memory
// Burst write from matrix C
writeC:
    for (int itr = 0, i = 0, j = 0; itr < dim * dim; itr++, j++) {
#pragma HLS LOOP_TRIPCOUNT min = c_dim* c_dim max = c_dim * c_dim
        if (j == dim) {
            j = 0;
            i++;
        }
        out_r[itr] = C[i * MAX_DIM + j];
    }
}

void matmul(int* C, int* A, int* B, int M) {
    for (int k = 0; k < M; k++) {
        for (int j = 0; j < M; j++) {
            for (int i = 0; i < M; i++) {
                C[k * M + j] += A[k * M + i] * B[i * M + j];
            }
        }
    }
}

int gen_random() {
    static default_random_engine e;
    static uniform_int_distribution<int> dist(0, 10);

    return dist(e);
}

void print(int* data, int columns, int rows) {
    vector<int> out(columns * rows);
    for (int r = 0; r < 10; r++) {
        for (int c = 0; c < 10; c++) {
            std::cout << std::setw(4) << data[r * columns + c] << " ";
        }
        std::cout << "…\n";
    }
    for (int r = 0; r < 10; r++) {
        std::cout << "   … ";
    }
    std::cout << "⋱\n\n";
}

void verify(vector<int>& gold, vector<int>& output) {
    for (int i = 0; i < (int)output.size(); i++) {
        if (output[i] != gold[i]) {
            std::cout << "Mismatch " << i << ": gold: " << gold[i] << " device: " << output[i] << "\n";
            print(output.data(), 16, 16);
            exit(EXIT_FAILURE);
        }
    }
}

int main() {

    static const int columns = 16;
    static const int rows = 16;
    vector<int> A(columns * rows);
    vector<int> B(columns * rows);
    vector<int> gold1(columns * rows, 0);
    vector<int> C(columns * rows, 0);
    vector<int> gold2(columns * rows, 0);

    generate(begin(A), end(A), gen_random);
    generate(begin(B), end(B), gen_random);

    std::cout << "A:\n";
    print(A.data(), columns, rows);

    std::cout << "B:\n";
    print(B.data(), columns, rows);

    matmul(gold1.data(), A.data(), B.data(), columns);
    std::cout << "Gold1:\n";
    print(gold1.data(), columns, rows);

    matmul_partition(A.data(), B.data(), C.data(), columns, MAX_DIM);

    verify(gold1, C);

    std::cout << "TEST PASSED\n\n";

    return EXIT_SUCCESS;
}

Array.array_partition_complete.matmul_pa.source_code:
void matmul_partition(int* in1, int* in2, int* out_r, int size, int rep_count) {
#pragma HLS INTERFACE m_axi port = in1 depth = 256
#pragma HLS INTERFACE m_axi port = in2 depth = 256
#pragma HLS INTERFACE m_axi port = out_r depth = 256

    // Local buffers to hold input data
    int A[MAX_SIZE][MAX_SIZE];
    int B[MAX_SIZE][MAX_SIZE];
    int C[MAX_SIZE][MAX_SIZE];
    int temp_sum[MAX_SIZE];

// partitioning Array B and C
#pragma HLS ARRAY_PARTITION variable = B dim = 2 complete
#pragma HLS ARRAY_PARTITION variable = C dim = 2 complete
#pragma HLS ARRAY_PARTITION variable = temp_sum dim = 1 complete

// Read data from global memory and write into local buffer for in1
read_A:
    for (int itr = 0, i = 0, j = 0; itr < size * size; itr++, j++) {
#pragma HLS LOOP_TRIPCOUNT min = c_dim* c_dim max = c_dim * c_dim
        if (j == size) {
            j = 0;
            i++;
        }
        A[i][j] = in1[itr];
    }

// Read data from global memory and write into local buffer for in2
read_B:
    for (int itr = 0, i = 0, j = 0; itr < size * size; itr++, j++) {
#pragma HLS LOOP_TRIPCOUNT min = c_dim* c_dim max = c_dim * c_dim
        if (j == size) {
            j = 0;
            i++;
        }
        B[i][j] = in2[itr];
    }

// Calculate matrix multiplication using local data buffer based on input size,
// and write results into local buffer for out
loop_count:
    for (int i = 0; i < rep_count; i++) {
    arraypart1:
        for (int row = 0; row < size; row++) {
#pragma HLS LOOP_TRIPCOUNT min = c_dim max = c_dim
        arraypart2:
            for (int col = 0; col < size; col++) {
#pragma HLS LOOP_TRIPCOUNT min = c_dim max = c_dim
            arraypart3:
                for (int j = 0; j < MAX_SIZE; j++) {
#pragma HLS LOOP_TRIPCOUNT min = c_dim max = c_dim
                    int result = (col == 0) ? 0 : temp_sum[j];
                    result += A[row][col] * B[col][j];
                    temp_sum[j] = result;
                    if (col == size - 1) C[row][j] = result;
                }
            }
        }
    }

// Write results from local buffer to global memory for out
writeC:
    for (int itr = 0, i = 0, j = 0; itr < size * size; itr++, j++) {
#pragma HLS LOOP_TRIPCOUNT min = c_dim* c_dim max = c_dim * c_dim
        if (j == size) {
            j = 0;
            i++;
        }
        out_r[itr] = C[i][j];
    }
}

void matmul(int* C, int* A, int* B, int M) {
    for (int k = 0; k < M; k++) {
        for (int j = 0; j < M; j++) {
            for (int i = 0; i < M; i++) {
                C[k * M + j] += A[k * M + i] * B[i * M + j];
            }
        }
    }
}

int gen_random() {
    static default_random_engine e;
    static uniform_int_distribution<int> dist(0, 10);

    return dist(e);
}

void print(int* data, int columns, int rows) {
    vector<int> out(columns * rows);
    for (int r = 0; r < 10; r++) {
        for (int c = 0; c < 10; c++) {
            std::cout << std::setw(4) << data[r * columns + c] << " ";
        }
        std::cout << "…\n";
    }
    for (int r = 0; r < 10; r++) {
        std::cout << "   … ";
    }
    std::cout << "⋱\n\n";
}

void verify(vector<int>& gold, vector<int>& output) {
    for (int i = 0; i < (int)output.size(); i++) {
        if (output[i] != gold[i]) {
            std::cout << "Mismatch " << i << ": gold: " << gold[i] << " device: " << output[i] << "\n";
            print(output.data(), 16, 16);
            exit(EXIT_FAILURE);
        }
    }
}

int main() {

    static const int columns = 16;
    static const int rows = 16;
    vector<int> A(columns * rows);
    vector<int> B(columns * rows);
    vector<int> gold1(columns * rows, 0);
    vector<int> C(columns * rows, 0);
    vector<int> gold2(columns * rows, 0);

    generate(begin(A), end(A), gen_random);
    generate(begin(B), end(B), gen_random);

    std::cout << "A:\n";
    print(A.data(), columns, rows);

    std::cout << "B:\n";
    print(B.data(), columns, rows);

    matmul(gold1.data(), A.data(), B.data(), columns);
    std::cout << "Gold1:\n";
    print(gold1.data(), columns, rows);

    matmul_partition(A.data(), B.data(), C.data(), columns, columns);

    verify(gold1, C);

    std::cout << "TEST PASSED\n\n";

