Interface.Memory.aliasing_axi_master_por.source_code:
void write(hls::stream<A_t> &inputStream, A_t *aximA,
           hls::stream<bool> &done) {
#pragma HLS INLINE OFF

    for (unsigned i=0; i<SIZE/RATIO; i++) {
    #pragma HLS PIPELINE
        aximA[i] = inputStream.read();
    }

    // Required to separate the write to aximA and write to done. 
    hls::fence(aximA, done);

    // This stream acts like a barrier to prevent the read process from
    // starting
    done.write(true);
}

void read(B_t *aximB, hls::stream<B_t> &outputStream,
          hls::stream<bool> &done)
{
#pragma HLS INLINE OFF 

    done.read();

    hls::fence(done, aximB); // Required to separate the read of done and read of aximB

    for (unsigned i=0; i<SIZE; i++) {
    #pragma HLS PIPELINE
        A_t tmp = aximB[i];
        outputStream << tmp;
    }
}

void dut(hls::stream<A_t> &inputStream, A_t *aximA, B_t *aximB,
         hls::stream<B_t> &outputStream) {
#pragma HLS INTERFACE axis  port=inputStream
#pragma HLS INTERFACE m_axi port=aximA depth=DEPTHA latency=8 offset=direct max_widen_bitwidth=128 max_read_burst_length=256 max_write_burst_length=256 bundle=axim1
#pragma HLS INTERFACE m_axi port=aximB depth=DEPTHB latency=8 offset=direct max_widen_bitwidth=128 max_read_burst_length=256 max_write_burst_length=256 bundle=axim2
#pragma HLS INTERFACE axis  port=outputStream

// The ALIAS pragma lets you treat aximA and aximB as pointers to the same memory location. 
#pragma HLS ALIAS ports=aximA,aximB distance=0

#pragma HLS DATAFLOW
    hls::stream<bool> done;

    write(inputStream, aximA, done);
    read(aximB, outputStream, done);
}

int main()
{

    void* axim = malloc(SIZE*sizeof(unsigned));
    A_t* aximA = (A_t*)axim;
    B_t* aximB = (B_t*)axim;
    hls::stream<A_t> in;
    hls::stream<B_t> out;

    // Create input stream data
    for (unsigned i=0; i<SIZE; i+=RATIO) {
        A_t temp; temp.data = 0;
        for (int j=RATIO-1; j>=0; j--) {
            A_t shift; shift.data = i+j;
            temp.data |= shift.data<<(sizeof(B_t)*8*j);
        }
        in << temp;
    }

    // Instantiate the top level function
    dut(in, aximA, aximB, out);

    // Check output stream data
    unsigned errors = 0;
    for (unsigned i=0; i<DEPTHB; i++) {
        unsigned temp = unsigned(out.read().data);
        if (temp != i) {
            std::cout << "ERROR: E " << i << ", A " << temp << std::endl;
            errors++;
        }
    }

    free(axim);
    if (errors) {
        std::cout << "FAILURE" << std::endl;
        return 1;
    }
    else {
        std::cout << "SUCCESS" << std::endl;
        return 0;
    }
}

Interface.Memory.burst_rw.vadd.vadd.source_code:
void vadd(int* a, int size, int inc_value) {
// Map pointer a to AXI4-master interface for global memory access
#pragma HLS INTERFACE m_axi port = a offset = slave bundle = gmem max_read_burst_length = 256 max_write_burst_length = 256 depth = 2048
// We also need to map a and return to a bundled axilite slave interface
#pragma HLS INTERFACE s_axilite port = a
#pragma HLS INTERFACE s_axilite port = size
#pragma HLS INTERFACE s_axilite port = inc_value
#pragma HLS INTERFACE s_axilite port = return

    int burstbuffer[BURSTBUFFERSIZE];

read_buf:
    // Per iteration of this loop perform BURSTBUFFERSIZE vector addition
    for (int i = 0; i < size; i += BURSTBUFFERSIZE) {
#pragma HLS LOOP_TRIPCOUNT min = c_size_min* c_size_min max = c_chunk_sz * c_chunk_sz / (c_size_max * c_size_max)
        int chunk_size = BURSTBUFFERSIZE;
        // boundary checks
        if ((i + BURSTBUFFERSIZE) > size) chunk_size = size - i;
        // burst read
        // Auto-pipeline is going to apply pipeline to these loops
        for (int j = 0; j < chunk_size; j++) {
// As the outer loop is not a perfect loop
#pragma HLS loop_flatten off
#pragma HLS LOOP_TRIPCOUNT min = c_size_min max = c_size_max
            burstbuffer[j] = a[i + j];
        }

    // calculate and write results to global memory, the sequential write in a for
    // loop can be inferred to a memory burst access
    calc_write:
        for (int j = 0; j < chunk_size; j++) {
#pragma HLS LOOP_TRIPCOUNT min = c_size_max max = c_chunk_sz
            burstbuffer[j] = burstbuffer[j] + inc_value;
            a[i + j] = burstbuffer[j];
        }
    }
}

