Misc.DSP_Intrinsic_Library.systolic_fir..source_code:
class FIR{
     private:
         const long* coeff_;
         long bias_;
         cascade<REG_A1|REG_B1|       REG_M|REG_P > dsp0;
         cascade<REG_A1|REG_B1|REG_B2|REG_M|REG_P > dsp_full[size - 1];
     public:
        FIR(const long* coeff, long bias)
            : coeff_(coeff), bias_(bias) {
#pragma HLS ARRAY_PARTITION variable=dsp_full complete dim=1
            };

        long fir(B_t input){

            auto out = dsp0.mul_add(coeff_[0], input, bias_);
            for(int j=1; j < size ; j++){
#pragma HLS unroll
                out = dsp_full[j - 1].mul_add(coeff_[j], out.bcout, out.pcout);
            }
            return out.pcout;
        };

};

void systolic_fir(

        long a[TAPS],
        long b[N], long c, long hw[N])
{
    #pragma HLS ARRAY_PARTITION variable=a complete dim=1
    FIR<TAPS> my_fir(a, c);

    LOOP_FIR:
    for(int i = 0 ; i< N ; i++){
        hw[i] = my_fir.fir(b[i]);
    }
}

int main(void) {
    long a[TAPS] = {1, 12, 3, 4};
    long b[N] = {2, 0, 0, 0, 3, -2, -7, 200, 12000, 64};
    long c = 0;
    long sw[N];
    long hw[N];

    class systolic_fir_sw{
        public:
            systolic_fir_sw(const long* coeff, int size)
                : coeff_(coeff), size_(size) {
                    shift_line_ = new long[size_];
                    for( int i = 0; i< size; ++i){
                        shift_line_[i] = 0;
                    }
                }
            ~systolic_fir_sw() {
                delete[] shift_line_;
            }
            long fir(long input) {
                for(int i = TAPS-1 ; i > 0 ; --i ){
                    shift_line_[i] = shift_line_[i - 1];
                }

                shift_line_[0] = input;

                long output = 0;
                for (int i = 0; i < size_; i++ ){
                    output += coeff_[i] * shift_line_[i];
                }
                return output;
            }
        private:
            const long* coeff_;
            long* shift_line_;
            int size_;
    };

    systolic_fir_sw fir_filter(a, TAPS);
    for (int i = 0 ; i < N; i ++){
        sw[i] = fir_filter.fir(b[i]);
    }

    systolic_fir(a,b, c, hw); // calling DUT

    for(int j = 0; j < N; j++){
        std::cout << "Input " << b[j] << ", Expect " << sw[j] << ", Got " << hw[j] << std::endl;
        if (hw[j] != sw[j]) {
            std::cout << "FAILED" << std::endl;
            return EXIT_FAILURE;
        }
    }
    std::cout << "PASS" << std::endl;
    return EXIT_SUCCESS;
}

class systolic_fir_sw{
    public:
        systolic_fir_sw(const long* coeff, int size)
            : coeff_(coeff), size_(size) {
                shift_line_ = new long[size_];
                for( int i = 0; i< size; ++i){
                    shift_line_[i] = 0;
                }
            }
        ~systolic_fir_sw() {
            delete[] shift_line_;
        }
        long fir(long input) {
            for(int i = TAPS-1 ; i > 0 ; --i ){
                shift_line_[i] = shift_line_[i - 1];
            }

            shift_line_[0] = input;

            long output = 0;
            for (int i = 0; i < size_; i++ ){
                output += coeff_[i] * shift_line_[i];
            }
            return output;
        }
    private:
        const long* coeff_;
        long* shift_line_;
        int size_;
};

Misc.DSP_Intrinsic_Library.transposed_fi.source_code:
C_t one_stage_mult_add(A_t a, B_t b, C_t in) {
    cascade<REG_A1 | REG_B1 | REG_M | REG_P> cas;
    R_t res = cas.mul_add(a, b, in);
    return res.pcout;
}

void transposed_fir( long &data_out, long data_in,
             long h0, long h1, long h2, long h3) {
    #pragma HLS pipeline II=1
    C_t pc_0_1, pc_1_2, pc_2_3, p_3;
    A_t data_in_fanout = data_in;
    pc_0_1 = one_stage_mult_add( h0, data_in_fanout, 0); // mul only so adds 0
    pc_1_2 = one_stage_mult_add( h1, data_in_fanout, pc_0_1);
    pc_2_3 = one_stage_mult_add( h2, data_in_fanout, pc_1_2);
    p_3    = one_stage_mult_add( h3, data_in_fanout, pc_2_3);
    data_out = p_3;
}

int main(void) {
    long h0=1,h1=2,h2=4,h3=8,hsum=h0+h1+h2+h3,errors=0;
    const int num=30;
    std::cout << "(i) init" << std::endl;

    for (int i = 0; i < num; i++) {
        long out,in;
        switch(i) {
            case 0: in=1; break;
            case num/3: in=10;break;
            case 2*num/3: in=100;break;
            default: in=0;
        }
        if (i>3*num/4) {
            in=i;
        }
        long expected= in*hsum;
        transposed_fir(out,in,h0,h1,h2,h3);
        std::cout << "(i) iteration "<<i<<" in "<<in<<" out " << out;
        if(out==expected) {
            std::cout << " (ok)" << std::endl;
        } else {
            errors++;
            std::cout << " expected " << expected << " error "<<errors << std::endl;
        }
    }
    if(errors>0) {
        std::cout << "(!) C-TB FAILED" << std::endl;
    } else {
        std::cout << "(i) C-TB PASS" << std::endl;
    }
    return errors;
}

Misc.fft.interface_array.fft_tb.main.source_code:
int main() {
    const int SIM_FRAMES = 20;
    const int SAMPLES = (1 << FFT_NFFT_MAX);

    int error_num = 0;
    bool ovflo_all = false;
    char res_filename[BUF_SIZE] = {0};
    char dat_filename[BUF_SIZE] = {0};
    static cmpxDataIn xn_input[SAMPLES];
    static cmpxDataOut xk_output[SAMPLES];

    for (int frame = 0; frame < SIM_FRAMES; ++frame) {
        int NFFT = 0;
        int CP_LEN =
            0; // length of the cyclic prefix to be inserted for each frame
        int FWD_INV = 0;
        int sc_sch = 0;
        int line_no = 1;
        FILE* stimfile;

        // Open stimulus .dat file for reading
        sprintf(dat_filename, "stimulus_%02d", frame);
        strcat(dat_filename, ".dat");
        stimfile = fopen(dat_filename, "r");

        int tmp_re, tmp_im;
        float dummy_re, dummy_im;
        const int max = 1 << FFT_INPUT_WIDTH; // might not work for > 32 bits!
        const int max_half_minus_one = (max / 2) - 1;
        // Scaling factor to get integer into -1 <= x < +1 range
        const double sc =
            ldexp(1.0, FFT_INPUT_WIDTH - 1); // might not work for > 32 bits!

        if (stimfile == NULL) {
            printf("ERROR: Can't open %s\n", dat_filename);
            exit(999);
        } else {
            printf("INFO: Reading %s ", dat_filename);
            while (fgetc(stimfile) != EOF && line_no < SAMPLES + 5) {
                switch (line_no) {
                case 1:
                    // Point size
                    fscanf(stimfile, "%X", &NFFT);
                    printf("NFFT %d ", NFFT);
                    break;
                case 2:
                    // CP length
                    fscanf(stimfile, "%X", &CP_LEN);
                    printf("CP_LEN %3d ", CP_LEN);
                    break;
                case 3:
                    // fwd-inv
                    fscanf(stimfile, "%X", &FWD_INV);
                    printf("FWD_INV %d ", FWD_INV);
                    break;
                case 4:
                    // Scaling schedule sc_sch
                    fscanf(stimfile, "%X", &sc_sch);
                    printf("sc_sch %X\n", sc_sch);
                    break;
                default:
                    // hex data (first 2 columns)
                    fscanf(stimfile, "%x %x %f %f", &tmp_re, &tmp_im, &dummy_re,
                           &dummy_im);
                    // printf("%x %x\n",tmp_re,tmp_im);

                    double input_data_re, input_data_im;
                    if (tmp_re > max_half_minus_one) {
                        input_data_re = ((tmp_re - 65536) / sc);
                    } else {
                        input_data_re = (tmp_re / sc);
                    }
                    // xn_input[line_no-5].re = input_data_re;
                    // xn_re_hw[line_no-5] = dummy_re;

                    if (tmp_im > max_half_minus_one) {
                        input_data_im = ((tmp_im - 65536) / sc);
                    } else {
                        input_data_im = (tmp_im / sc);
                    }
                    // xn_input[line_no-5].im = input_data_im;
                    // xn_im_hw[line_no-5] = dummy_im;

                    xn_input[line_no - 5] =
                        cmpxDataIn(input_data_re, input_data_im);
                }
                line_no++;
            }
        }
        fclose(stimfile);

        bool ovflo;

        fft_top(FWD_INV, xn_input, xk_output, &ovflo);

        ovflo_all |= ovflo;

        // Open golden results .res file for reading
        FILE* resfile;
        sprintf(res_filename, "stimulus_%02d", frame);
        strcat(res_filename, ".res");
        if ((resfile = fopen(res_filename, "r")) == 0) {
            printf("ERROR: Can't open %s\n", res_filename);
            exit(888);
        }

        int tmp;
        fscanf(resfile, "%X", &tmp);
        fscanf(resfile, "%X", &tmp);
        for (int i = 0; i < (1 << NFFT); i++) {
            fscanf(resfile, "%x %x %f %f", &tmp_re, &tmp_im, &dummy_re,
                   &dummy_im);
            data_out_t golden = dummy_re;
            // if (golden != xk_output[i].re)
            if (golden != xk_output[i].real()) {
                error_num++;
                cout << "Frame:" << frame << " index: " << i
                     << "  Golden: " << golden.to_float()
                     << " vs. RE Output: " << setprecision(14)
                     << xk_output[i].real().to_float() << endl;
            }
            golden = dummy_im;
            // if (golden != xk_output[i].im)
            if (golden != xk_output[i].imag()) {
                error_num++;
                cout << "Frame:" << frame << " index: " << i
                     << "  Golden: " << golden.to_float()
                     << " vs. IM Output: " << setprecision(14)
                     << xk_output[i].imag().to_float() << endl;
            }
        }
        fclose(resfile);
    }

    cout << " ERRORS: " << error_num << endl;
    if (error_num > 0)
        cout << " (FAILED!!!)" << endl;
    else if (ovflo_all)
        cout << " (OVERFLOW!!!)" << endl;
    else
        cout << " (PASSED!!!)" << endl;

    if (error_num > 0)
        return 1;
    else
        return 0;
}

