bool close_enough(float a, float b) {
    const float epsilon=(1+0.5/100); // 0.5% absolute difference
    if ( a>-0.0 ) {
        // positive
        if ( b < a*epsilon && a < b*epsilon ) return true; else return false;
    } else {
        // negative, changing order
        if ( b > a*epsilon && a > b*epsilon ) return true; else return false;
    }
}

