Pipelining.Functions.hier_func.hier_func.source_code:
void sumsub_func(din_t* in1, din_t* in2, dint_t* outSum, dint_t* outSub) {
    *outSum = *in1 + *in2;
    *outSub = *in1 - *in2;
}

void shift_func(dint_t* in1, dint_t* in2, dout_t* outA, dout_t* outB) {
    *outA = *in1 >> 1;
    *outB = *in2 >> 2;
}

void hier_func4(din_t A, din_t B, dout_t* C, dout_t* D) {
    dint_t apb, amb;

    sumsub_func(&A, &B, &apb, &amb);
#ifndef __SYNTHESIS__
    FILE* fp1;
    char filename[255];
    sprintf(filename, "Out_apb_%03d.dat", apb);
    fp1 = fopen(filename, "w");
    fprintf(fp1, "%d \n", apb);
    fclose(fp1);
#endif
    shift_func(&apb, &amb, C, D);
}

int main() {
    // Data storage
    int a[NUM_TRANS], b[NUM_TRANS];
    int c_expected[NUM_TRANS], d_expected[NUM_TRANS];
    int c[NUM_TRANS], d[NUM_TRANS];

    // Function data (to/from function)
    int a_actual, b_actual;
    int c_actual, d_actual;

    // Misc
    int retval = 0, i, i_trans, tmp;
    FILE* fp;

    // Load input data from files
    fp = fopen("tb_data/inA.dat", "r");
    for (i = 0; i < NUM_TRANS; i++) {
        fscanf(fp, "%d", &tmp);
        a[i] = tmp;
    }
    fclose(fp);

    fp = fopen("tb_data/inB.dat", "r");
    for (i = 0; i < NUM_TRANS; i++) {
        fscanf(fp, "%d", &tmp);
        b[i] = tmp;
    }
    fclose(fp);

    // Execute the function multiple times (multiple transactions)
    for (i_trans = 0; i_trans < NUM_TRANS - 1; i_trans++) {

        // Apply next data values
        a_actual = a[i_trans];
        b_actual = b[i_trans];

        hier_func4(a_actual, b_actual, &c_actual, &d_actual);

        // Store outputs
        c[i_trans] = c_actual;
        d[i_trans] = d_actual;
    }

    // Load expected output data from files
    fp = fopen("tb_data/outC.golden.dat", "r");
    for (i = 0; i < NUM_TRANS; i++) {
        fscanf(fp, "%d", &tmp);
        c_expected[i] = tmp;
    }
    fclose(fp);

    fp = fopen("tb_data/outD.golden.dat", "r");
    for (i = 0; i < NUM_TRANS; i++) {
        fscanf(fp, "%d", &tmp);
        d_expected[i] = tmp;
    }
    fclose(fp);

    // Check outputs against expected
    for (i = 0; i < NUM_TRANS - 1; ++i) {
        if (c[i] != c_expected[i]) {
            retval = 1;
        }
        if (d[i] != d_expected[i]) {
            retval = 1;
        }
    }

    // Print Results
    if (retval == 0) {
        printf("    *** *** *** *** \n");
        printf("    Results are good \n");
        printf("    *** *** *** *** \n");
    } else {
        printf("    *** *** *** *** \n");
        printf("    Mismatch: retval=%d \n", retval);
        printf("    *** *** *** *** \n");
    }

    // Return 0 if outputs are correct
    return retval;
}

