void write(hls::stream<int> &inputStream, int A[N][N], hls::stream<int> &line) {
#pragma HLS INLINE OFF

    for (unsigned int i=0; i < N; ++i) {
#pragma HLS PIPELINE II=3 // move to inner loop 
        for (unsigned int j=0; j < N; ++j) {
            int temp = inputStream.read();
            std::cout << "Write: Reading A[" << i << "][" << j << "] = " << temp << std::endl;
            A[i][j] = temp;
        }

        // This is to create a cycle delay between the write to A and the write to line.
        ap_wait();
        // This stream acts like a barrier to prevent the read process from
        // starting to read a row early. 
        line.write(i);
    }

}

void read(int A[N][N], hls::stream<int> &outputStream, hls::stream<int> &line)
{
#pragma HLS INLINE OFF 
    int row;
    do {
#pragma HLS PIPELINE II=3
        row = line.read(); // This gates this process. 
        for (unsigned j=0; j < N; ++j) {
            int temp = A[row][j];
            std::cout << "Read: Writing A[" << row << "][" << j << "] = " << temp << std::endl;
            outputStream << temp;
        }
    } while (row < N-1);
}

void dut(hls::stream<int> &inputStream, int A[N][N], hls::stream<int> &outputStream) {
#pragma HLS INTERFACE axis  port=inputStream
#pragma HLS INTERFACE m_axi port=A 
#pragma HLS INTERFACE axis  port=outputStream
//#pragma HLS STABLE variable=A
#pragma HLS DATAFLOW

    hls::stream<int> line;

    write(inputStream, A, line);
    read(A, outputStream, line);
}

int main()
{

    int A[N][N];
    hls::stream<int> in;
    hls::stream<int> out;

    // Create input stream data
    for (unsigned int i=0; i < N; ++i) {
        for (unsigned int j=0; j < N; ++j) {
            std::cout << "TB: Writing (" << i << "," << j << ") = " << i+j << std::endl;
            in << i+j;
        }
    }

    // Instantiate the top level function
    dut(in, A, out);

    // Check output stream data
    unsigned errors = 0;
    for (unsigned i=0; i < N; ++i) {
        for (unsigned j=0; j < N; ++j) {
            unsigned temp = out.read();
            if (temp != i+j) {
                std::cout << "ERROR: A[" << i << "][" << j << "] does not match" << std::endl;
                errors++;
            }
        }
    }

    if (errors) {
        std::cout << "FAILURE" << std::endl;
        return 1;
    }
    else {
        std::cout << "SUCCESS" << std::endl;
        return 0;
    }
}

