void krnl_stream_vdatamover(hls::stream<pkt> &in,
                      hls::stream<pkt> &out,
					            int mem[DATA],
                      hls::ap_hs<int> &reset_value, // output
                      hls::ap_hs<int> &reset_myCounter // input 
                      ) {
#pragma HLS interface mode=axis port=in
#pragma HLS interface mode=axis port=out
#pragma HLS INTERFACE m_axi port = mem 

static int counter; 
bool eos = false;

pkt t_out;
for(int i=0;i<DATA;i++)
{
  ap_uint<DWIDTH> tmpOut;
      pkt t1 = in.read();
    if(reset_myCounter.valid())
    {
      int reset = reset_myCounter.read();
      if(reset == 1)
      {
        ap_uint<DWIDTH> i1 = t1.data;
        tmpOut = i1+mem[i];
        t_out.data = tmpOut;
        t_out.last = t1.last;
        out.write(t_out);
        counter =0;
        reset_value.write(counter);
        break;
      }
    }

    if(counter==threshold)
    {
      reset_value.write(counter);
      break;
    }
    counter++;
    // Packet for output

    reset_value.write(counter);
    // Reading data from input packet
    ap_uint<DWIDTH> in1 = t1.data;

    // Vadd operation
     tmpOut = in1+mem[i];

    // Setting data and configuration to output packet
    t_out.data = tmpOut;
    t_out.last = t1.last;
    t_out.keep = -1; // Enabling all bytes

    // Writing packet to output stream
    out.write(t_out);

    if (t1.last) {
      eos = true;
    }
}
 }

int main(){
	hls::ap_hs<int> reset_value;
	hls::ap_hs<int> reset_myCounter;
    hls::stream<packet> in, out;
    int mem[DATA];
    for(int i =0;i<4999;i++)
    {
        reset_myCounter.write(0);
    }
    reset_myCounter.write(1);

    packet tmp1, tmp2,tmp3;
  //  hls::stream<packet> in, out;
    for (unsigned i = 0; i < 5000; i++) {
        tmp1.data = i;
        tmp1.keep = -1;
        tmp1.strb = 1;
        tmp1.user = 1;

            if(i==DATA-1)
                tmp1.last = 1;
            else 
                tmp1.last =0;
        in.write(tmp1);
        mem[i] = i;
    }   
    int err=0;

krnl_stream_vdatamover(in,out,mem,reset_value,reset_myCounter);
    vector<int> reset_mem;
 for (unsigned i = 0; i < 5000; i++) {
        out.read(tmp2);
        reset_mem.push_back(reset_value.read());
        if(tmp2.data != i*2)
        {
            cout << "ERROR: results mismatch" << endl;
            cout << "i *2 =" << i*2;
            cout << " != ";
            cout << "tmp2.data=" << tmp2.data << endl;
            err=1;
            break;
        }
    }
    for(int i=0;i<reset_mem.size();i++)
    {
        if(i == reset_mem.size()-1)
        {
            if(reset_mem[i] !=0)
            {
                cout << "ERROR during the threshold value = " << reset_mem[i] ;
                err=1;
                break;
            }
        }
    }
	return err;
}

